const tonweb = require('tonweb');
const { Cell } = tonweb.boc;
const { Address } = tonweb.utils;

async function main() {
  try {
    const codeHex = '';
    const c = Cell.oneFromBoc(codeHex);
    console.log('1. Code parsed OK');
    
    // Test NftCollection
    const provider = new tonweb.HttpProvider('https://toncenter.com/api/v2/jsonRPC');
    const NftCollection = tonweb.token.nft.NftCollection;
    const collection = new NftCollection(provider, {
      ownerAddress: new Address('UQDCW7waS_aHBTsCXrqT76kY6lIsFqQJW_YRlEWGV4Rpp653'),
      collectionContentUri: 'https://arweave.net/test',
      nftItemContentBaseUri: 'https://arweave.net/',
      royalty: 0.05,
      royaltyAddress: new Address('UQDb6dm0keTz7-Nhy9ERtbj3YxKblmTj1SzlORL6x4XUwrQI'),
    });
    console.log('2. NftCollection created OK');
    
    const addr = await collection.getAddress();
    console.log('3. Address:', addr.toString(true,true,true));
    
    // Try createStateInit
    const si = await collection.createStateInit();
    console.log('4. StateInit created OK');
    
  } catch(e) {
    console.error('ERROR:', e.message);
    console.error(e.stack?.split('\n').slice(0,4).join('\n'));
  }
}
main();
